const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const lines = stdout.trim().split('\n');
try {
  const d = JSON.parse(lines[lines.length - 1]);
  if (d.error) {
    throw new Error('Voiceover step failed: ' + d.error);
  }
  const result = { ...d, run_id: $('Parse Gate Approval').first().json.run_id };
  return [{ json: result }];
} catch(e) {
  // Try to extract error from stderr if stdout parsing failed
  const errMatch = stderr.match(/Error: (.+)/);
  const errMsg = errMatch ? errMatch[1] : (e.message || 'Unknown voiceover error');
  throw new Error('Parse voiceover failed: ' + errMsg);
}

// Mattermost sends POST with {context: {action, gate, run_id, ...}, post_id, user_name}
const input = $input.first().json;
const ctx = input.context || input.body?.context || input.body || input.query || input;
const gate = parseInt(ctx.gate || '0');
const names = {0:'Plan',1:'News',2:'Script',3:'Voiceover',4:'Footage',5:'Video',6:'Publish'};
return [{json: {success: false, message: '❌ Rejected at Gate ' + gate + ' (' + names[gate] + ').', gate, run_id: ctx.run_id || '', post_id: input.post_id || input.body?.post_id || '', user_name: input.user_name || input.body?.user_name || ''}}];

// Extract trigger_id from Mattermost button click
const input = $input.first().json;
const body = input.body || input;
const triggerId = body.trigger_id || '';
const ctx = body.context || {};
const gate = ctx.gate !== undefined ? ctx.gate : 0;
const runId = ctx.run_id || '';

if (!triggerId) {
  return [{ json: { error: 'No trigger_id in request', body: JSON.stringify(body).slice(0, 500) } }];
}

// Call Mattermost API to open interactive dialog
const mmUrl = 'http://192.168.0.11:8065';
const botToken = '61hukqibxini5yci6nkf7oio7c';

const dialogPayload = {
  trigger_id: triggerId,
  url: 'http://192.168.0.11:5678/webhook/instagram-dialog-submit',
  dialog: {
    callback_id: 'comment_gate_' + gate + '_' + runId,
    title: '\u{1F4AC} \u062a\u0639\u0644\u064a\u0642 \u2014 Gate ' + gate,
    submit_label: '\u0625\u0631\u0633\u0627\u0644',
    state: JSON.stringify({ gate: gate, run_id: runId }),
    elements: [
      {
        display_name: '\u0627\u0644\u062a\u0639\u0644\u064a\u0642',
        name: 'comment_text',
        type: 'textarea',
        placeholder: '\u0627\u0643\u062a\u0628 \u062a\u0639\u0644\u064a\u0642\u0643 \u0647\u0646\u0627...',
        optional: false
      }
    ]
  }
};

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: mmUrl + '/api/v4/actions/dialogs/open',
  headers: {
    'Authorization': 'Bearer ' + botToken,
    'Content-Type': 'application/json'
  },
  body: dialogPayload,
  returnFullResponse: true,
  ignoreHttpStatusErrors: true,
});

return [{ json: { status: 'dialog_opened', gate, run_id: runId, mm_status: resp.statusCode || 'unknown' } }];

// Parse dialog submission from Mattermost
const input = $input.first().json;
const body = input.body || input;

// Mattermost dialog_submission payload
const submission = body.submission || {};
const state = JSON.parse(body.state || '{}');
const commentText = submission.comment_text || '';

return [{ json: {
  gate: parseInt(state.gate || '0'),
  run_id: state.run_id || '',
  comment: commentText,
  action: 'comment'
}}];

